import{_ as a,c as n,o as e,V as s}from"./chunks/framework.1sOznGPE.js";const u=JSON.parse('{"title":"npx","description":"","frontmatter":{},"headers":[],"relativePath":"guide/node/npm/npx.md","filePath":"guide/node/npm/npx.md","lastUpdated":1718632692000}'),p={name:"guide/node/npm/npx.md"},i=s(`<h1 id="npx" tabindex="-1">npx <a class="header-anchor" href="#npx" aria-label="Permalink to &quot;npx&quot;">​</a></h1><h2 id="npx是什么" tabindex="-1">npx是什么 <a class="header-anchor" href="#npx是什么" aria-label="Permalink to &quot;npx是什么&quot;">​</a></h2><p>npx是一个命令行工具，它是npm 5.2.0版本中新增的功能。它允许用户在不安装全局包的情况下，运行已安装在本地项目中的包或者远程仓库中的包。</p><p>npx的作用是在命令行中运行node包中的可执行文件，而不需要全局安装这些包。这可以使开发人员更轻松地管理包的依赖关系，并且可以避免全局污染的问题。它还可以帮助开发人员在项目中使用不同版本的包，而不会出现版本冲突的问题。</p><h2 id="npx-的优势" tabindex="-1">npx 的优势 <a class="header-anchor" href="#npx-的优势" aria-label="Permalink to &quot;npx 的优势&quot;">​</a></h2><ol><li>避免全局安装：<code>npx</code> 允许你执行npm package，而不需要你先全局安装它。</li><li>总是使用最新版本：如果你没有在本地安装相应的npm package，<code>npx</code> 会从npm的package仓库中下载并使用最新版。</li><li>执行任意npm包：<code>npx</code> 不仅可以执行在 <code>package.json</code> 的 <code>scripts</code> 部分定义的命令，还可以执行任何npm package。</li><li>执行GitHub gist：<code>npx</code>甚至可以执行GitHub gist或者其他公开的JavaScript文件。</li></ol><blockquote><p>npx 的运行规则和 npm 是一样的本地目录查找.bin 看有没有 如果没有就去全局的node_moduels 查找，如果还没有就去下载这个包然后运行命令，然后删除这个包</p></blockquote><h2 id="npm-和-npx-区别" tabindex="-1">npm 和 npx 区别 <a class="header-anchor" href="#npm-和-npx-区别" aria-label="Permalink to &quot;npm 和 npx 区别&quot;">​</a></h2><p>npm 和 npm 是Node.js生态系统中的两个不同的命令行工具，它们有不同的用途和行为：</p><ul><li><p>npm（Node Package Manager）：npm是Node.js的默认包管理器，用于管理项目中的依赖项。它允许你安装、更新和移出包，还可以运行定义在 <code>package.json</code> 文件中的脚本。<strong>重在安装，并不具备执行某个模块的功能。</strong></p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install lodash # 安装lodash</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run dev #运行 package.json 中定义的 dev 命令</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div></li><li><p>npx（Node Package Execute）：npx是npm 5.2.0及更高版本中引入的一个工具，它用于在不全局安装包的情况下执行包的二进制文件。npx可以运行发布在 npm 上的包，无论这些包是否已经安装在本地。如果包没有在本地安装，npx将临时安装它并运行，运行完成后不会在本地保留这些包，特别适合运行单次命令、创建项目脚手架，或者运行不经常使用的工具。<strong>虽然会自动安装模块，但是重在执行某个命令。</strong></p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create-react-app my-react # 使用 create-react-app 创建一个新的 react 应用</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> eslint --init # 运行 eslint 的初始化命令</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div></li></ul>`,10),t=[i];function l(o,d,c,r,h,m){return e(),n("div",null,t)}const x=a(p,[["render",l]]);export{u as __pageData,x as default};
